import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [clicked, setClicked] = useState(false);

  return (
    <motion.section
      initial={{ backgroundColor: "transparent", scale: 1 }}
      whileHover={{
        backgroundColor: "#6B8746", // tono verde de la imagen
        color: "#ffffff"
      }}
      animate={{ scale: clicked ? 1.14 : 1 }}
      transition={{ duration: clicked ? 0.2 : 0.3 }}
      onClick={() => {
        setClicked(true);
        setTimeout(() => setClicked(false), 400); // ahora más tiempo (0.4s)
      }}
      style={{
        cursor: "pointer",
        borderRadius: "1rem",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        padding: "2rem",
        maxWidth: "1400px",
        margin: "0 auto 6rem",
        flexWrap: "wrap",
        color: "black",
        transition: "all 0.3s ease-in-out",
        ...style,
      }}
    >
      {/* Fuerza títulos a negro */}
      <div style={{ color: "inherit" }}>
        {children}
      </div>
    </motion.section>
  );
};

export default AnimatedSection;
